import React, { useState, useCallback } from 'react';
import { uploadPhotosForAttendance } from '../services/apiService';

const PhotoUpload = ({ classId, onAttendanceMarked }) => {
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processedResults, setProcessedResults] = useState(null);
  const [dragActive, setDragActive] = useState(false);
  const [error, setError] = useState(null);

  const handleDrag = useCallback((e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const handleDrop = useCallback((e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    
    const files = Array.from(e.dataTransfer.files);
    const imageFiles = files.filter(file => file.type.startsWith('image/'));
    
    if (imageFiles.length === 0) {
      setError('Please select valid image files');
      return;
    }
    
    if (imageFiles.length > 20) {
      setError('Maximum 20 files allowed at once');
      return;
    }
    
    setSelectedFiles(imageFiles);
    setError(null);
  }, []);

  const handleFileSelect = (e) => {
    const files = Array.from(e.target.files);
    const imageFiles = files.filter(file => file.type.startsWith('image/'));
    
    if (imageFiles.length === 0) {
      setError('Please select valid image files');
      return;
    }
    
    if (imageFiles.length > 20) {
      setError('Maximum 20 files allowed at once');
      return;
    }
    
    setSelectedFiles(imageFiles);
    setError(null);
  };

  const processUploadedPhotos = async () => {
    if (selectedFiles.length === 0) {
      setError('Please select at least one photo');
      return;
    }

    if (!classId) {
      setError('Class ID is required');
      return;
    }

    setIsProcessing(true);
    setError(null);
    
    try {
      console.log(`Converting ${selectedFiles.length} files to base64...`);
      
      const imageDataArray = await Promise.all(
        selectedFiles.map(file => convertFileToBase64(file))
      );

      console.log('Base64 conversion complete, sending to API...');

      const requestData = {
        images: imageDataArray,
        classId: classId,
        uploadType: 'batch',
        timestamp: new Date().toISOString()
      };

      console.log('Request data:', {
        imagesCount: requestData.images.length,
        classId: requestData.classId,
        uploadType: requestData.uploadType
      });

      const response = await uploadPhotosForAttendance(requestData);

      console.log('API response:', response);

      if (response.success) {
        setProcessedResults(response.results);
        showUploadResults(response.results);
        onAttendanceMarked(response.results.recognizedStudents || []);
        setError(null);
      } else {
        const errorMessage = response.message || 'Failed to process photos';
        setError(errorMessage);
        console.error('Processing failed:', response);
      }

    } catch (error) {
      console.error('Upload processing error:', error);
      const errorMessage = error.response?.data?.message || error.message || 'Failed to process uploaded photos';
      setError(errorMessage);
    } finally {
      setIsProcessing(false);
    }
  };

  const convertFileToBase64 = (file) => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result);
      reader.onerror = error => reject(error);
    });
  };

  const showUploadResults = (results) => {
    const modal = document.createElement('div');
    modal.className = 'results-modal';
    modal.style.cssText = `
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0, 0, 0, 0.7);
      display: flex;
      justify-content: center;
      align-items: center;
      z-index: 1000;
    `;
    
    modal.innerHTML = `
      <div class="modal-content" style="
        background: white;
        padding: 2rem;
        border-radius: 10px;
        max-width: 600px;
        max-height: 80vh;
        overflow-y: auto;
        position: relative;
      ">
        <div class="modal-header" style="
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 1.5rem;
          border-bottom: 1px solid #eee;
          padding-bottom: 1rem;
        ">
          <h3 style="margin: 0; color: #333;">📊 Upload Processing Results</h3>
          <button class="close-btn" style="
            background: #f44336;
            color: white;
            border: none;
            width: 30px;
            height: 30px;
            border-radius: 50%;
            cursor: pointer;
            font-size: 18px;
            font-weight: bold;
          " onclick="this.parentElement.parentElement.parentElement.remove()">×</button>
        </div>
        <div class="results-summary" style="margin-bottom: 1.5rem;">
          <div class="summary-cards" style="
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 1rem;
            margin-bottom: 1rem;
          ">
            <div class="summary-card" style="
              background: #e3f2fd;
              padding: 1rem;
              border-radius: 5px;
              text-align: center;
            ">
              <div class="card-number" style="
                font-size: 2rem;
                font-weight: bold;
                color: #1976d2;
              ">${results.totalPhotosProcessed || 0}</div>
              <div class="card-label" style="
                color: #666;
                font-size: 0.9rem;
              ">Photos Processed</div>
            </div>
            <div class="summary-card" style="
              background: #fff3e0;
              padding: 1rem;
              border-radius: 5px;
              text-align: center;
            ">
              <div class="card-number" style="
                font-size: 2rem;
                font-weight: bold;
                color: #f57c00;
              ">${results.totalFacesDetected || 0}</div>
              <div class="card-label" style="
                color: #666;
                font-size: 0.9rem;
              ">Faces Detected</div>
            </div>
            <div class="summary-card success" style="
              background: #e8f5e8;
              padding: 1rem;
              border-radius: 5px;
              text-align: center;
            ">
              <div class="card-number" style="
                font-size: 2rem;
                font-weight: bold;
                color: #4caf50;
              ">${(results.recognizedStudents || []).length}</div>
              <div class="card-label" style="
                color: #666;
                font-size: 0.9rem;
              ">Students Recognized</div>
            </div>
            <div class="summary-card" style="
              background: #f3e5f5;
              padding: 1rem;
              border-radius: 5px;
              text-align: center;
            ">
              <div class="card-number" style="
                font-size: 2rem;
                font-weight: bold;
                color: #9c27b0;
              ">${(results.markedAttendance || []).length}</div>
              <div class="card-label" style="
                color: #666;
                font-size: 0.9rem;
              ">Attendance Marked</div>
            </div>
          </div>
        </div>
        ${(results.recognizedStudents && results.recognizedStudents.length > 0) ? `
        <div class="recognized-students">
          <h4 style="margin-bottom: 1rem; color: #333;">Recognized Students:</h4>
          <div class="students-grid" style="
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
            gap: 0.5rem;
          ">
            ${results.recognizedStudents.map(student => `
              <div class="student-card" style="
                background: #f9f9f9;
                padding: 0.75rem;
                border-radius: 5px;
                border-left: 3px solid #4caf50;
              ">
                <div class="student-name" style="
                  font-weight: bold;
                  color: #333;
                  margin-bottom: 0.25rem;
                ">${student.name || 'Unknown'}</div>
                <div class="student-id" style="
                  color: #666;
                  font-size: 0.9rem;
                  margin-bottom: 0.25rem;
                ">${student.studentId || student.student_id || 'N/A'}</div>
                <div class="confidence" style="
                  color: #4caf50;
                  font-size: 0.85rem;
                  font-weight: bold;
                ">${student.confidence ? (student.confidence * 100).toFixed(1) + '%' : 'N/A'} confidence</div>
              </div>
            `).join('')}
          </div>
        </div>
        ` : '<p style="text-align: center; color: #666;">No students were recognized in the uploaded photos.</p>'}
      </div>
    `;
    
    document.body.appendChild(modal);
    
    // Auto-remove after 15 seconds
    setTimeout(() => {
      if (modal.parentElement) {
        modal.remove();
      }
    }, 15000);

    // Close on outside click
    modal.addEventListener('click', (e) => {
      if (e.target === modal) {
        modal.remove();
      }
    });
  };

  const removeFile = (index) => {
    setSelectedFiles(prev => prev.filter((_, i) => i !== index));
    setError(null);
  };

  const clearResults = () => {
    setProcessedResults(null);
    setError(null);
  };

  return (
    <div className="photo-upload-container" style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
      <div className="upload-header" style={{ textAlign: 'center', marginBottom: '2rem' }}>
        <h2 style={{ color: '#333', marginBottom: '0.5rem' }}>📁 Photo Upload Attendance</h2>
        <p style={{ color: '#666', fontSize: '1rem' }}>
          Upload individual photos or group photos for batch attendance marking
        </p>
      </div>

      {error && (
        <div className="error-message" style={{
          background: '#ffebee',
          color: '#c62828',
          padding: '1rem',
          borderRadius: '5px',
          marginBottom: '1rem',
          border: '1px solid #ef9a9a'
        }}>
          ❌ {error}
        </div>
      )}

      <div 
        className={`upload-zone ${dragActive ? 'drag-active' : ''}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
        style={{
          border: `2px dashed ${dragActive ? '#4caf50' : '#ddd'}`,
          borderRadius: '10px',
          padding: '3rem',
          textAlign: 'center',
          background: dragActive ? '#f1f8e9' : '#fafafa',
          transition: 'all 0.3s ease',
          marginBottom: '2rem'
        }}
      >
        <input
          type="file"
          multiple
          accept="image/*"
          onChange={handleFileSelect}
          className="file-input"
          id="photo-upload"
          style={{ display: 'none' }}
        />
        <label htmlFor="photo-upload" style={{ cursor: 'pointer' }}>
          <div className="upload-content">
            <div className="upload-icon" style={{ fontSize: '4rem', marginBottom: '1rem' }}>📁</div>
            <h3 style={{ margin: '1rem 0', color: '#333' }}>Drag & Drop Photos Here</h3>
            <p style={{ margin: '0.5rem 0', color: '#666', fontSize: '1.1rem' }}>or click to select files</p>
            <div className="upload-hints" style={{ 
              display: 'flex', 
              flexWrap: 'wrap', 
              justifyContent: 'center', 
              gap: '1rem',
              marginTop: '1rem',
              fontSize: '0.9rem',
              color: '#777'
            }}>
              <span>✓ Supports JPG, PNG, GIF</span>
              <span>✓ Multiple photos allowed</span>
              <span>✓ Group photos supported</span>
              <span>✓ Maximum 20 files at once</span>
            </div>
          </div>
        </label>
      </div>

      {selectedFiles.length > 0 && (
        <div className="selected-files" style={{ marginBottom: '2rem' }}>
          <div className="files-header" style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center',
            marginBottom: '1rem'
          }}>
            <h3 style={{ margin: 0, color: '#333' }}>Selected Photos ({selectedFiles.length})</h3>
            <button
              onClick={() => {
                setSelectedFiles([]);
                setError(null);
              }}
              className="clear-all-btn"
              style={{
                background: '#f44336',
                color: 'white',
                border: 'none',
                padding: '0.5rem 1rem',
                borderRadius: '5px',
                cursor: 'pointer'
              }}
            >
              Clear All
            </button>
          </div>
          
          <div className="file-preview-grid" style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
            gap: '1rem',
            marginBottom: '2rem'
          }}>
            {selectedFiles.map((file, index) => (
              <div key={index} className="file-preview" style={{
                border: '1px solid #ddd',
                borderRadius: '8px',
                overflow: 'hidden',
                background: 'white'
              }}>
                <img 
                  src={URL.createObjectURL(file)} 
                  alt={`Preview ${index + 1}`}
                  className="preview-image"
                  style={{
                    width: '100%',
                    height: '120px',
                    objectFit: 'cover'
                  }}
                />
                <div className="file-info" style={{ padding: '0.5rem' }}>
                  <div className="file-name" style={{ 
                    fontSize: '0.8rem',
                    color: '#333',
                    marginBottom: '0.25rem',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                  }}>{file.name}</div>
                  <div style={{ 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center' 
                  }}>
                    <span className="file-size" style={{ 
                      fontSize: '0.75rem', 
                      color: '#666' 
                    }}>
                      {(file.size / 1024 / 1024).toFixed(2)} MB
                    </span>
                    <button 
                      onClick={() => removeFile(index)}
                      className="remove-btn"
                      style={{
                        background: '#f44336',
                        color: 'white',
                        border: 'none',
                        borderRadius: '50%',
                        width: '20px',
                        height: '20px',
                        cursor: 'pointer',
                        fontSize: '12px'
                      }}
                    >
                      ×
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
          
          <div style={{ textAlign: 'center' }}>
            <button
              onClick={processUploadedPhotos}
              disabled={isProcessing}
              className="process-btn"
              style={{
                background: isProcessing ? '#ccc' : '#4caf50',
                color: 'white',
                border: 'none',
                padding: '1rem 2rem',
                borderRadius: '8px',
                cursor: isProcessing ? 'not-allowed' : 'pointer',
                fontSize: '1.1rem',
                fontWeight: 'bold',
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                margin: '0 auto'
              }}
            >
              {isProcessing ? (
                <>
                  <div className="btn-spinner" style={{
                    width: '20px',
                    height: '20px',
                    border: '2px solid #fff',
                    borderTop: '2px solid transparent',
                    borderRadius: '50%',
                    animation: 'spin 1s linear infinite'
                  }}></div>
                  Processing Photos...
                </>
              ) : (
                <>
                  🔍 Process Attendance ({selectedFiles.length} photos)
                </>
              )}
            </button>
          </div>
        </div>
      )}

      {processedResults && (
        <div className="processing-results" style={{
          background: '#f9f9f9',
          padding: '1.5rem',
          borderRadius: '8px',
          border: '1px solid #ddd'
        }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center',
            marginBottom: '1rem'
          }}>
            <h3 style={{ margin: 0, color: '#333' }}>Processing Results Summary</h3>
            <button
              onClick={clearResults}
              style={{
                background: '#2196f3',
                color: 'white',
                border: 'none',
                padding: '0.5rem 1rem',
                borderRadius: '5px',
                cursor: 'pointer'
              }}
            >
              Clear Results
            </button>
          </div>
          <div className="results-summary-compact" style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
            gap: '1rem'
          }}>
            <div className="result-item" style={{
              display: 'flex',
              justifyContent: 'space-between',
              padding: '0.75rem',
              background: 'white',
              borderRadius: '5px'
            }}>
              <span className="result-label" style={{ color: '#666' }}>Photos Processed:</span>
              <span className="result-value" style={{ fontWeight: 'bold', color: '#333' }}>
                {processedResults.totalPhotosProcessed || 0}
              </span>
            </div>
            <div className="result-item" style={{
              display: 'flex',
              justifyContent: 'space-between',
              padding: '0.75rem',
              background: 'white',
              borderRadius: '5px'
            }}>
              <span className="result-label" style={{ color: '#666' }}>Faces Detected:</span>
              <span className="result-value" style={{ fontWeight: 'bold', color: '#333' }}>
                {processedResults.totalFacesDetected || 0}
              </span>
            </div>
            <div className="result-item success" style={{
              display: 'flex',
              justifyContent: 'space-between',
              padding: '0.75rem',
              background: '#e8f5e8',
              borderRadius: '5px'
            }}>
              <span className="result-label" style={{ color: '#2e7d32' }}>Students Recognized:</span>
              <span className="result-value" style={{ fontWeight: 'bold', color: '#2e7d32' }}>
                {(processedResults.recognizedStudents || []).length}
              </span>
            </div>
            <div className="result-item" style={{
              display: 'flex',
              justifyContent: 'space-between',
              padding: '0.75rem',
              background: 'white',
              borderRadius: '5px'
            }}>
              <span className="result-label" style={{ color: '#666' }}>Attendance Marked:</span>
              <span className="result-value" style={{ fontWeight: 'bold', color: '#333' }}>
                {(processedResults.markedAttendance || []).length}
              </span>
            </div>
          </div>
        </div>
      )}

      <style jsx>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default PhotoUpload;
